import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Breadcrumbs.module.css';

export type BreadcrumbsRootProps = HTMLArkProps<'nav'>;
export type BreadcrumbsListProps = HTMLArkProps<'ol'>;
export type BreadcrumbsItemProps = HTMLArkProps<'li'>;
export type BreadcrumbsLinkProps = HTMLArkProps<'a'>;
export type BreadcrumbsPageProps = HTMLArkProps<'span'>;
export type BreadcrumbsSeparatorProps = HTMLArkProps<'li'>;
export type BreadcrumbsEllipsisProps = HTMLArkProps<'span'>;

const BreadcrumbsRoot = forwardRef<HTMLElement, BreadcrumbsRootProps>(function BreadcrumbsRoot(
  { className, 'aria-label': ariaLabel = 'Breadcrumb', ...props },
  ref,
) {
  return (
    <ark.nav
      ref={ref}
      data-scope="breadcrumbs"
      data-part="root"
      data-slot="breadcrumbs-root"
      aria-label={ariaLabel}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const BreadcrumbsList = forwardRef<HTMLOListElement, BreadcrumbsListProps>(function BreadcrumbsList(
  { className, ...props },
  ref,
) {
  return (
    <ark.ol
      ref={ref}
      data-scope="breadcrumbs"
      data-part="list"
      data-slot="breadcrumbs-list"
      className={clsx(styles.list, normalizeClassName(className))}
      {...props}
    />
  );
});

const BreadcrumbsItem = forwardRef<HTMLLIElement, BreadcrumbsItemProps>(function BreadcrumbsItem(
  { className, ...props },
  ref,
) {
  return (
    <ark.li
      ref={ref}
      data-scope="breadcrumbs"
      data-part="item"
      data-slot="breadcrumbs-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const BreadcrumbsLink = forwardRef<HTMLAnchorElement, BreadcrumbsLinkProps>(
  function BreadcrumbsLink({ className, ...props }, ref) {
    return (
      <ark.a
        ref={ref}
        data-scope="breadcrumbs"
        data-part="link"
        data-slot="breadcrumbs-link"
        className={clsx(styles.link, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const BreadcrumbsPage = forwardRef<HTMLSpanElement, BreadcrumbsPageProps>(function BreadcrumbsPage(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="breadcrumbs"
      data-part="page"
      data-slot="breadcrumbs-page"
      aria-current="page"
      className={clsx(styles.page, normalizeClassName(className))}
      {...props}
    />
  );
});

const BreadcrumbsSeparator = forwardRef<HTMLLIElement, BreadcrumbsSeparatorProps>(
  function BreadcrumbsSeparator({ className, children = '/', ...props }, ref) {
    return (
      <ark.li
        ref={ref}
        data-scope="breadcrumbs"
        data-part="separator"
        data-slot="breadcrumbs-separator"
        aria-hidden="true"
        className={clsx(styles.separator, normalizeClassName(className))}
        {...props}
      >
        {children}
      </ark.li>
    );
  },
);

const BreadcrumbsEllipsis = forwardRef<HTMLSpanElement, BreadcrumbsEllipsisProps>(
  function BreadcrumbsEllipsis({ className, children = '...', ...props }, ref) {
    return (
      <ark.span
        ref={ref}
        data-scope="breadcrumbs"
        data-part="ellipsis"
        data-slot="breadcrumbs-ellipsis"
        aria-hidden="true"
        className={clsx(styles.ellipsis, normalizeClassName(className))}
        {...props}
      >
        {children}
      </ark.span>
    );
  },
);

const Breadcrumbs = Object.assign(BreadcrumbsRoot, {
  Root: BreadcrumbsRoot,
  List: BreadcrumbsList,
  Item: BreadcrumbsItem,
  Link: BreadcrumbsLink,
  Page: BreadcrumbsPage,
  Separator: BreadcrumbsSeparator,
  Ellipsis: BreadcrumbsEllipsis,
});

export { Breadcrumbs };

@layer ui.components {
  .root[data-scope='breadcrumbs'][data-part='root'] {
    max-width: var(--breadcrumbs-max-width, 100%);
    color: var(--breadcrumbs-color, var(--color-muted-foreground));
    font-size: var(--breadcrumbs-font-size, var(--text-sm));
    line-height: var(--breadcrumbs-line-height, var(--line-height-text-sm));
  }

  .list[data-scope='breadcrumbs'][data-part='list'] {
    display: flex;
    min-width: 0;
    align-items: center;
    gap: var(--breadcrumbs-gap, var(--spacing-1));
    margin: 0;
    padding: 0;
    list-style: none;
    white-space: nowrap;

    > .item:last-child {
      flex: 1 1 auto;
      max-width: var(--breadcrumbs-item-max-width, 16rem);
    }
  }

  .item[data-scope='breadcrumbs'][data-part='item'] {
    display: inline-flex;
    min-width: 0;
    flex: 0 0 auto;
    align-items: center;
  }

  .link[data-scope='breadcrumbs'][data-part='link'],
  .page[data-scope='breadcrumbs'][data-part='page'] {
    display: block;
    min-width: 0;
    max-width: 100%;
    padding-inline: var(--breadcrumbs-item-padding-x, 0.25rem);
    white-space: nowrap;
  }

  .link[data-scope='breadcrumbs'][data-part='link'],
  .page[data-scope='breadcrumbs'][data-part='page'],
  .ellipsis[data-scope='breadcrumbs'][data-part='ellipsis'] {
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .link[data-scope='breadcrumbs'][data-part='link'] {
    color: var(--breadcrumbs-link-color, var(--color-muted-foreground));
    text-decoration: var(--breadcrumbs-link-text-decoration, none);
    text-underline-offset: var(--breadcrumbs-link-underline-offset, 0.2em);
    border-radius: var(--breadcrumbs-link-radius, var(--radius-sm));
    outline: none;
    transition: var(--breadcrumbs-link-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        color: var(--breadcrumbs-link-color-hover, var(--color-foreground));
        text-decoration: var(--breadcrumbs-link-text-decoration-hover, none);
      }
    }

    &:focus-visible {
      box-shadow: 0 0 0 var(--breadcrumbs-focus-ring-width, var(--border-width-sm))
        var(--breadcrumbs-focus-ring-color, var(--color-ring));
    }
  }

  .page[data-scope='breadcrumbs'][data-part='page'] {
    color: var(--breadcrumbs-page-color, var(--color-foreground));
    font-weight: var(--breadcrumbs-page-font-weight, var(--weight-medium));
  }

  .separator[data-scope='breadcrumbs'][data-part='separator'] {
    display: inline-flex;
    align-items: center;
    color: var(--breadcrumbs-separator-color, var(--color-muted-foreground));
    font-size: var(--breadcrumbs-separator-font-size, 0.875em);
    line-height: 1;
    user-select: none;
  }

  .ellipsis[data-scope='breadcrumbs'][data-part='ellipsis'] {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: var(--breadcrumbs-ellipsis-size, 1rem);
    min-height: var(--breadcrumbs-ellipsis-size, 1rem);
    padding-inline: var(--breadcrumbs-item-padding-x, 0.25rem);
    color: var(--breadcrumbs-ellipsis-color, var(--color-muted-foreground));
    border-radius: var(--breadcrumbs-ellipsis-radius, var(--radius-sm));
    transition: background-color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--color-accent);
      }
    }
  }
}

export { Breadcrumbs } from './Breadcrumbs';

export type {
  BreadcrumbsRootProps,
  BreadcrumbsListProps,
  BreadcrumbsItemProps,
  BreadcrumbsLinkProps,
  BreadcrumbsPageProps,
  BreadcrumbsSeparatorProps,
  BreadcrumbsEllipsisProps,
} from './Breadcrumbs';
